// // This module implements a 16-bit register that loads data from 'd' on the negative edge of 'clk' when 'en' is low, and clears to 0 when 'clr' is low.
module register_16bit(
    input [15:0] d,
    input clk,
    input en,
    input clr,
    output reg [15:0] q
);

    always @(posedge clk) begin
        if (clr)
            q <= 16'b0;
        else if (en)
            q <= d;
    end

endmodule
